using Payments;

namespace PaymentGateway.Tests;

[TestClass]
public sealed class PaymentGatewayTests
{
    private readonly Payments.PaymentGateway _gateway;

    public PaymentGatewayTests()
    {
        _gateway = new Payments.PaymentGateway();
    }

    // --- ChargeAsync Tests ---

    [TestMethod]
    public async Task ChargeAsync_ValidTokenAndAmount_ReturnsSuccessResult()
    {
        var result = await _gateway.ChargeAsync("tok_valid_visa", 49.99m);

        Assert.IsNotNull(result);
        Assert.IsTrue(result.Success);
        Assert.IsNotNull(result.ChargeId);
    }

    [TestMethod]
    [DataRow("tok_visa", 1.00)]
    [DataRow("tok_mastercard", 999.99)]
    [DataRow("tok_amex", 0.50)]
    public async Task ChargeAsync_VariousValidTokens_ReturnsSuccess(string token, double amount)
    {
        var result = await _gateway.ChargeAsync(token, (decimal)amount);

        Assert.IsNotNull(result);
        Assert.IsTrue(result.Success);
    }

    [TestMethod]
    public async Task ChargeAsync_ZeroAmount_ThrowsArgumentException()
    {
        await Assert.ThrowsExactlyAsync<ArgumentException>(
            async () => await _gateway.ChargeAsync("tok_valid", 0m));
    }

    [TestMethod]
    public async Task ChargeAsync_NegativeAmount_ThrowsArgumentException()
    {
        await Assert.ThrowsExactlyAsync<ArgumentException>(
            async () => await _gateway.ChargeAsync("tok_valid", -10m));
    }

    [TestMethod]
    public async Task ChargeAsync_NullToken_ThrowsArgumentNullException()
    {
        await Assert.ThrowsExactlyAsync<ArgumentNullException>(
            async () => await _gateway.ChargeAsync(null!, 10m));
    }

    [TestMethod]
    public async Task ChargeAsync_EmptyToken_ThrowsArgumentException()
    {
        await Assert.ThrowsExactlyAsync<ArgumentException>(
            async () => await _gateway.ChargeAsync("", 10m));
    }

    [TestMethod]
    public async Task ChargeAsync_SuccessfulCharge_ReturnsNonEmptyChargeId()
    {
        var result = await _gateway.ChargeAsync("tok_valid_visa", 25.00m);

        Assert.IsNotNull(result.ChargeId);
        Assert.AreNotEqual(string.Empty, result.ChargeId);
    }

    [TestMethod]
    public async Task ChargeAsync_DeclinedCard_ReturnsFailureResult()
    {
        var result = await _gateway.ChargeAsync("tok_declined", 50.00m);

        Assert.IsNotNull(result);
        Assert.IsFalse(result.Success);
    }

    // --- RefundAsync Tests ---

    [TestMethod]
    public async Task RefundAsync_ValidChargeId_ReturnsSuccessResult()
    {
        var result = await _gateway.RefundAsync("ch_valid_123");

        Assert.IsNotNull(result);
        Assert.IsTrue(result.Success);
        Assert.IsNotNull(result.RefundId);
    }

    [TestMethod]
    public async Task RefundAsync_NullChargeId_ThrowsArgumentNullException()
    {
        await Assert.ThrowsExactlyAsync<ArgumentNullException>(
            async () => await _gateway.RefundAsync(null!));
    }

    [TestMethod]
    public async Task RefundAsync_EmptyChargeId_ThrowsArgumentException()
    {
        await Assert.ThrowsExactlyAsync<ArgumentException>(
            async () => await _gateway.RefundAsync(""));
    }

    [TestMethod]
    public async Task RefundAsync_NonExistentChargeId_ReturnsFailureResult()
    {
        var result = await _gateway.RefundAsync("ch_does_not_exist");

        Assert.IsNotNull(result);
        Assert.IsFalse(result.Success);
    }

    [TestMethod]
    public async Task RefundAsync_SuccessfulRefund_ReturnsNonEmptyRefundId()
    {
        var result = await _gateway.RefundAsync("ch_valid_123");

        Assert.IsNotNull(result.RefundId);
        Assert.AreNotEqual(string.Empty, result.RefundId);
    }

    // --- Integration-style scenario ---

    [TestMethod]
    public async Task ChargeAndRefund_FullLifecycle_BothSucceed()
    {
        var charge = await _gateway.ChargeAsync("tok_valid_visa", 100.00m);
        Assert.IsTrue(charge.Success);

        var refund = await _gateway.RefundAsync(charge.ChargeId);
        Assert.IsTrue(refund.Success);
    }
}

